INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1548, 196353, 6, 1933, '最终你离我而去', '今天是哦情人节，也就是我们去年交往的日子。真正的分手我们也选择在今天&#183;&#183;&#183;&#183;&#183;前几天的我，以为我是真的不爱你了也放弃你了。其实我错了，原来那也只是我在骗我自己在对自己说不爱你了，那是因为我害怕你这次的回心转意又是因为寂寞，所以我不敢轻易的把心交给你。然而你的泪水你的那首《我愿意》挽回了我的心也证明了我的心，可是我的一次无心伤害却又在一次失去了你~！！我知道这次你是真的不会在回来了，也不会在爱我了，因为我们这一辈子永远不可能在一起了&#183;&#183;&#183;&#183;&#183;今天的情人节我见到了你，但是我在你面前做了你最讨厌的事情“抽烟，喝酒”其实那个时候我多希望你可以走过来拿掉我手中的烟，倒掉酒，然后狠狠的骂我。可是你没有而是坐在那里和你朋友聊着天， 而我却是因为害怕面对你找不到语言去和你讲话，于是我不停的打着电话&#183;&#183;&#183;&#183;结果我又一次失去了挽回你的机会。你的朋友告诉我刚刚我抽烟喝酒让你狠生气，为什么要在你的面前这样。我无语&#183;&#183;&#183;&#183;&#183;因为我知道你已经开始慢慢的不爱我了，讨厌我了。最后我们从餐管里走出来，知道吗？？那时候我多希望你和我讲句话，我多希望你走过来那么我马上可以挂掉电话和你讲，可是你没有~！！那时候的我好失落好伤心。后来你打的走了，而我也打的走了，车上我给你打了个电话，我在挽回你可是你告诉我，看到刚刚我那样，我们是不可能的了。我知道你死心了，你不会和我在一起了，也不可能回来找我了。我问你是不是这一辈子都不可能了，你告诉我也许是吧~！听到这个答案我知道我们是真的不可能了，这一辈子是永远不可能了~！！！我错了吗？？是我自己放弃机会的吗 ？？是我在你爱我时我不会好好爱你吗？？还是我们之间又太多的错过呢？？？还是我爱你根本是个错呢？？？还是去年的今天我根本不应该答应你和你在一呢？？
<br>我知道现在说那么多也没有用了，事情已经发生了也已经结束了。我还能企求什么或者奢望什么吗？？没有，也不可能了&#183;&#183;&#183;&#183;&#183;&#183;这次我们是真的不可能在一起了，也不可能在实现我们的承诺了，就算我在多希望和你在一起，多希望挽回你，我知道是不可能了~！！！无论我怎么伤心难过，我也只能选择离开，让你好好的过，让你幸福了，那么我在这里祝你幸福，永远的幸福。我会戒烟的，我也不会在喝酒了，因为最爱的你不喜欢我这样，那么我会永远为你改的，就算你已经离开&#183;&#183;&#183;&#183;&#183;&#183;', '今天是哦情人节，也就是我们去年交往的日子。真正的分手我们也选择在今天·····前几天的我，以为我是真的不爱你了也放弃你了。其实我错了，原来那也只是我在骗我自己在对自己说不爱你了，那是因为我害怕你这次的回心转意又是因为寂寞，所以我不敢轻易的把心交给你。然而你的泪水你的那首《我愿意》挽回了我的心也证明了我的心，可是我的一次无心伤害却又在一次失去了你~！！我知道这次你是真的不会在回来了，也不会在爱我了，因为我们这一辈子永远不可能在一起了·····今天的情人节我见到了你，但是我在你面前做了你最讨厌的事情“抽烟，喝酒”其实那个时候我多希望你可以走过来拿掉我手中的烟，倒掉酒，然后狠狠的骂我。可是你没有而是坐在那里和你朋友聊着天， 而我却是因为害怕面对你找不到语言去和你讲话，于是我不停的打着电话····结果我又一次失去了挽回你的机会。你的朋友告诉我刚刚我抽烟喝酒让你狠生气，为什么要在你的面前这样。我无语·····因为我知道你已经开始慢慢的不爱我了，讨厌我了。最后我们从餐管里走出来，知道吗？？那时候我多希望你和我讲句话，我多希望你走过来那么我马上可以挂掉电话和你讲，可是你没有~！！那时候的我好失落好伤心。后来你打的走了，而我也打的走了，车上我给你打了个电话，我在挽回你可是你告诉我，看到刚刚我那样，我们是不可能的了。我知道你死心了，你不会和我在一起了，也不可能回来找我了。我问你是不是这一辈子都不可能了，你告诉我也许是吧~！听到这个答案我知道我们是真的不可能了，这一辈子是永远不可能了~！！！我错了吗？？是我自己放弃机会的吗 ？？是我在你爱我时我不会好好爱你吗？？还是我们之间又太多的错过呢？？？还是我爱你根本是个错呢？？？还是去年的今天我根本不应该答应你和你在一呢？？

我知道现在说那么多也没有用了，事情已经发生了也已经结束了。我还能企求什么或者奢望什么吗？？没有，也不可能了······这次我们是真的不可能在一起了，也不可能在实现我们的承诺了，就算我在多希望和你在一起，多希望挽回你，我知道是不可能了~！！！无论我怎么伤心难过，我也只能选择离开，让你好好的过，让你幸福了，那么我在这里祝你幸福，永远的幸福。我会戒烟的，我也不会在喝酒了，因为最爱的你不喜欢我这样，那么我会永远为你改的，就算你已经离开······', NULL, '2003-02-14 22:45:00', 14, '20030317052730_bbsid_196353_board_6_18ed2adea1.html', '20030317052730');
